import UIKit
import CryptoKit

class CryptoWallet {
    private var privateKey: SecKey?
    private var publicKey: SecKey?

    init() {
        generateKeyPair()
    }

    private func generateKeyPair() {
        let keyAttributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256
        ]
        
        SecKeyGeneratePair(keyAttributes as CFDictionary, &publicKey, &privateKey)
    }

    func getPublicKey() -> Data? {
        guard let pubKey = publicKey else { return nil }
        return SecKeyCopyExternalRepresentation(pubKey, nil) as Data?
    }

    func signTransaction(data: Data) -> Data? {
        guard let privKey = privateKey else { return nil }
        var error: Unmanaged<CFError>?
        guard let signature = SecKeyCreateSignature(privKey, .ecdsaSignatureMessageX962SHA256, data as CFData, &error) else { return nil }
        return signature as Data
    }

    func verifyTransaction(data: Data, signature: Data) -> Bool {
        guard let pubKey = publicKey else { return false }
        var error: Unmanaged<CFError>?
        return SecKeyVerifySignature(pubKey, .ecdsaSignatureMessageX962SHA256, data as CFData, signature as CFData, &error)
    }
}

class BlockchainCommunicator {
    func sendTransaction(transactionData: Data, completion: @escaping (Bool) -> Void) {
        // Simulated blockchain communication
        let url = URL(string: "https://blockchain.example.com/sendTransaction")!
